def spn_cbc_decrypt(sbox, perm, master_key, num_rounds, iv, ciphertext):
    def rotate_left_32(val, shift):
        shift %= 32
        if shift == 0:
            return val
        return ((val << shift) | (val >> (32 - shift))) & 0xFFFFFFFF

    # Key schedule
    round_keys = []
    for i in range(num_rounds + 1):
        rotated = rotate_left_32(master_key, i * 4)
        round_keys.append((rotated >> 16) & 0xFFFF)

    # Inverse S-box
    inv_sbox = [0] * 16
    for i in range(16):
        inv_sbox[sbox[i]] = i

    # Inverse permutation
    inv_perm = [0] * 16
    for i in range(16):
        inv_perm[perm[i]] = i

    def sbox_layer(block, sb):
        result = 0
        for n in range(4):
            nibble = (block >> (n * 4)) & 0xF
            result |= sb[nibble] << (n * 4)
        return result

    def perm_layer(block, p):
        result = 0
        for i in range(16):
            if block & (1 << i):
                result |= 1 << p[i]
        return result

    def ecb_decrypt_block(block):
        block ^= round_keys[num_rounds]
        for r in range(num_rounds - 1, -1, -1):
            block = perm_layer(block, inv_perm)
            block = sbox_layer(block, inv_sbox)
            block ^= round_keys[r]
        return block

    # CBC decryption
    plaintext = []
    prev = iv
    for c in ciphertext:
        p = ecb_decrypt_block(c) ^ prev
        plaintext.append(p)
        prev = c

    return plaintext
